def icon(name: str, size: int = 16, color: str = "currentColor") -> str:
    """Return an inline SVG icon string."""
    svg = ICONS.get(name, ICONS["info"])
    return svg.replace("{s}", str(size)).replace("{c}", color)


def icon_html(name: str, size: int = 16, color: str = "currentColor",
              valign: str = "middle", style: str = "") -> str:
    """Return icon wrapped in a span for inline use."""
    svg = icon(name, size, color)
    return f'<span style="display:inline-flex;align-items:center;vertical-align:{valign};{style}">{svg}</span>'


def icon_label(icon_name: str, label: str, size: int = 15,
               icon_color: str = "currentColor", gap: str = "7px",
               label_style: str = "") -> str:
    """Return icon + text label side by side."""
    return (
        f'<span style="display:inline-flex;align-items:center;gap:{gap};">'
        f'{icon(icon_name, size, icon_color)}'
        f'<span style="{label_style}">{label}</span>'
        f'</span>'
    )
